var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"정말 괜찮은 거 맞아? 그 자식이 너한테 나쁜 짓을 하진 않았어?","JPN":"本当に大丈夫なの？　あいつに何か悪いことはされてない？","ENG":"Are you really okay? Did she do anything bad to you?","TWN":"真的沒事嗎？那傢伙沒有對你做壞事吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 괜찮아요.","JPN":"私は平気です！","ENG":"I'm okay.","TWN":"我沒事。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 만든 샌드위치를 그 애가 한 입 먹고 버린 것만 빼면요.","JPN":"私が作ったサンドイッチをあの子が食べ残したこと以外は。","ENG":"Aside from the fact that she threw away the sandwich I made for her.","TWN":"除了她吃了我做的三明治後又扔掉了之外。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"오오, 진짜잖아?","JPN":"おお、本当だ。","ENG":"Oh, oh, that's really true?","TWN":"哇，真的耶？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 음식물의 정체가 뭔진 모르겠지만, 절단면에 이빨 자국이 남아있어.","JPN":"この食べ物の正体はわからないが、切断面に歯形が残っている。","ENG":"I'm not sure what this food is, but there are traces of chewing on the cut surface.","TWN":"雖然不知道這食物的真面目，但切面上留下了咀嚼的痕跡。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"사람을 보고도 무작정 공격하지 않은 데다가, 음식을 먹으려고 시도하다니- 확실히 특이한 케이스네요.","JPN":"人を見てもむやみに攻撃せず、食べ物を食べてみようとするとは、確かに珍しいケースです。","ENG":"She didn't attack you on sight and even tried to eat food. This is definitely an unusual case.","TWN":"看到人也沒有貿然攻擊，還試圖吃東西——確實是個特殊的案例呢。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 개체는… 인간과 화합하며 살아가기 위해 인간의 음식을 섭취하길 노력했던 게 분명해.","JPN":"この個体は……人間と仲良く生きていくために人間の食べ物を食べようと努力したに違いない。","ENG":"This entity... clearly tried to live in harmony with humans by consuming human food.","TWN":"這個個體……顯然是為了與人類和諧共處而努力嘗試吃人類的食物。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"네? 그거 정말이에요?","JPN":"は？　それって本当ですか？","ENG":"Really? Is that true?","TWN":"啊？那是真的嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L12_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"개인의 헛된 망상일 뿐이니 신경 쓰지 마세요.","JPN":"個人のバカバカしい妄想に過ぎませんので、気にしなくていいですよ。","ENG":"It's just one individual's misguided delusion, so don't pay attention to it.","TWN":"只是個人的妄想而已，不用在意。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"하지만 사람과의 진짜 대화가 가능한 개체라는 건, 이걸로 증명됐군요.","JPN":"でも本当に人と対話できる個体だということは、これで証明されました。","ENG":"But this proves that the entity can truly communicate with humans.","TWN":"但是能夠與人進行真正對話的個體，這一點已經證明了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 침식체는 절대 없애면 안 돼요.","JPN":"この侵食体は絶対倒してはいけません。","ENG":"This C.O. must not be eliminated.","TWN":"這個侵蝕體絕對不能消滅。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"반드시 포획해서 연구해야 합니다.","JPN":"必ず捕獲して研究すべきです。","ENG":"We must capture her and conduct research.","TWN":"必須捕獲進行研究。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"연구가 목적이라면 잔해를 확보하는 것만으로도 충분해요.","JPN":"研究目的なら残骸を確保するだけでも十分です。","ENG":"If the goal is research, securing some remains would be enough.","TWN":"如果目的是研究，只要確保殘骸就足夠了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"굳이 침식체를 살려두는 위험을 감수할 필요는 없죠.","JPN":"あえて侵食体を生かしておくような危険を冒す必要はありません。","ENG":"There's no need to risk keeping the C.O. alive.","TWN":"沒必要冒著留下侵蝕體的危險。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"크으윽…!","JPN":"くううっ……！","ENG":"Kgh...!","TWN":"呃…！"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"아하하… 다들 진정하세요.","JPN":"あはは……みんな落ち着いて。","ENG":"Ah hah hah... Calm down, everyone.","TWN":"啊哈哈……大家冷靜一下。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"음?","JPN":"あら？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이 화분… 멀쩡하네.","JPN":"この植木鉢……元気だね。","ENG":"This flowerpot... It's intact.","TWN":"這花盆……完好無損。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"솔로베, 이 꽃. 이전에 운석이 추락했을 때도 시든 적 없었지?","JPN":"ソロベー、この花。以前隕石が落下したときも枯れてなかったよね？","ENG":"Solovey, this flower. It didn't wither when the meteorite fell before, right?","TWN":"蘇羅薇，這朵花。之前隕石墜落時也沒有枯萎過吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네! 지금처럼 싱싱했어요. 물은 꾸준히 줬거든요.","JPN":"あ、はい！　今みたいに生き生きしてました。水やりも忘れませんでしたよ。","ENG":"Yes! It was as fresh as it is now. I never forget to water it.","TWN":"啊，是的！就像現在一樣新鮮。我沒有忘記澆水。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"무너진 집을 다시 찾아갔을 때, 그 커다란 식물은 시들고 있었어.","JPN":"壊れた家を再度訪れた時、あの大きな植物は朽ちかけてた。","ENG":"When I went back to the collapsed house, the giant plant was decaying.","TWN":"當我再次找到那座倒塌的房子時，那巨大的植物正在腐爛。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"왜 이 꽃만 두 번씩이나 멀쩡한 거지?","JPN":"どうしてこの花だけが2回とも元気なんだろう？","ENG":"But why is it that only this flower remains intact, twice?","TWN":"可是，為什麼那傢伙去過的地方，這朵花竟然兩次都完好無損呢？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"구획 봉쇄가 끝났대요. 태스크포스들이 진을 치고 있으니 안에서 녀석을 찾기만 하면 됩니다.","JPN":"区画封鎖が終わったようです。タスクフォースが陣を張っているので、その中でやつを探してください。","ENG":"The blockade around the block is complete. The TASKFORCEs are stationed, so all we need to do is find her inside.","TWN":"區域封鎖已經結束。特遣勢力正在佈署，只要在裡面找到那傢伙就行了。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"침식체라면 봐줄 필요 없겠지? 바로 처치해주겠어.","JPN":"侵食体相手に手加減は無用よね？　すぐに倒してやるわ。","ENG":"There's no need to show mercy to a C.O., right? I'll eliminate her right away.","TWN":"如果是侵蝕體的話，就沒必要手下留情了吧？我會立刻解決它。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"워낙 신출귀몰해서 쉽진 않을 거예요. 도시의 카메라들을 전부 뒤져도 녀석을 못 찾았으니까요.","JPN":"神出鬼没ですからそう簡単には捕まらないと思います。都市のカメラをすべて確認しても見つけられませんでした。","ENG":"She's incredibly elusive, so it won't be simple. Even after checking all the city cameras, we couldn't track her down.","TWN":"她神出鬼沒的，不太好找。我們已經翻遍了城市的所有監視器，也沒能找到她。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"카메라가 안 된다면 잔류 침식파를 확인해보죠. 마침 휴대용 침식파 분석기를 가져왔거든요.","JPN":"カメラがだめなら残留侵食波を確認しましょう。ちょうど携帯用の侵食波の分析器を持ってきています。","ENG":"If the cameras don't help, let's check the Corruption ray residuals. I just happened to have brought a portable Corruption ray analyzer.","TWN":"監視器不行的話，那就檢查一下殘留的侵蝕波吧。正好我帶了可擕式侵蝕波分析儀。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"조교야?","JPN":"助手？","ENG":"Yoonjung?","TWN":"助教？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"네… 넵! 바로 준비하겠습니다!","JPN":"は……はい！　すぐ用意するっす！","ENG":"Y-yes! I'll prepare it right now!","TWN":"是……是！我馬上準備！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이 화면의 먹물 자국이 전부 그 침식체 녀석이 남긴 건가요?","JPN":"この画面の墨のような跡が全部あの侵食体が残したものですか？","ENG":"Are all the ink marks on this screen left by that C.O.?","TWN":"這螢幕上的墨漬都是那個侵蝕體留下的嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"맞아요, 경관님. 침식파는 침식체가 남기는 발자국 같은 거죠.","JPN":"そうなんですよ、お巡りさん。侵食波は侵食体が残した足跡みたいなものなんです。","ENG":"That's right, officer. Corruption rays are like the footprints left by C.O.s.","TWN":"沒錯，警官。侵蝕波就像是侵蝕體留下的足跡一樣。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그리고 이 탐지 범위를 확대해보면, 어디로 움직였는지도…","JPN":"そしてこの探知範囲を拡大すると、どこに動いたのかも……","ENG":"And if we expand the detection range, we can see where she moved...","TWN":"而且如果擴大這個探測範圍，還能知道她去了哪裡…"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"어머?","JPN":"あら？","ENG":"Oh?","TWN":"哎呀？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"이 영악한 친구, 장난을 칠 줄 아나 보네요.","JPN":"このずる賢い子、遊び方を知っているようですね。","ENG":"This clever one seems to know how to play tricks.","TWN":"這狡猾的傢伙，看來還會混淆視聽呢。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흔적이… 세 갈래로 나뉘어 있잖아?","JPN":"痕跡が……3つに分かれている？","ENG":"The traces... They've split into three directions!","TWN":"痕跡…分成了三條路？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"1번 구역 수색조, 아직까진 특이사항 없음.","JPN":"1番エリア捜索班、現在まで異常なし。","ENG":"Sector 1 search team reporting no unusual findings so far.","TWN":"1號區域搜索隊，目前沒有異常情況。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"3번 구역도 1차 수색을 끝마쳤지만 침식파는 탐지가 안 됐습니다.","JPN":"3番エリアも1次捜索を完了しましたが、侵食波は探知できませんでした。","ENG":"The first search has been completed in Sector 3, but no Corruption rays were detected.","TWN":"3號區域的第一次搜查已經結束，沒有探測到侵蝕波。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"알겠습니다. 꼭 침식 흔적이 아니라더라도 거동수상자를 발견하면 알려주세요.","JPN":"わかりました。侵食の痕跡がなくても挙動不審な人がいたら教えてください。","ENG":"All right. Please inform me if you find any suspicious individuals, even if they're not related to Corruption traces.","TWN":"知道了。即使不是侵蝕痕跡，發現可疑人物也請告知我。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LOOP"},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아-","JPN":"わあ～","ENG":"Wow!","TWN":"哇啊-"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"좀 전엔 그렇게 많던 사람들이 거리에 하나도 안 보여요.","JPN":"さっきまであんなに多かった人が街に1人もいません。","ENG":"There were so many people just a moment ago, and now there's not a single person on the street.","TWN":"剛才還那麼多人的街道上，現在一個人都看不到了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"대피령을 내렸으니 당연하지.","JPN":"避難令を出したからね。","ENG":"Of course. We issued an evacuation order.","TWN":"那當然了，撤離令都已經下達了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"도시관리국의 지시를 어기고 여기에 남아있는 건 멍청이들뿐이니까.","JPN":"都市管理局の指示を聞かずにここに残っているのはバカだけよ。","ENG":"Those who ignore the orders of the City Management and remain here are nothing but fools.","TWN":"只有傻子才會違背城市管理局的指示留在這裡的。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"흐음- 멍청이구나.","JPN":"ふ～ん、バカなんだ。","ENG":"Hmm... Fools.","TWN":"哼嗯，真是個傻子。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님. 어린 친구한테 나쁜 표현은 가르치지 말자고요.","JPN":"警視様。子どもに変な表現を教えないでくださいよ。","ENG":"Major, let's not teach the young one bad expressions.","TWN":"長官，不要教小朋友這些奇怪的話。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐, 왜? 내가 틀린 말한 것도 아니잖아.","JPN":"ふん、別に間違ってはいないでしょう。","ENG":"Hmph, why? I didn't say anything incorrect.","TWN":"哼，我也沒說錯什麼。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이 앞이 침식체가 마지막으로 포착됐던 장소에요.","JPN":"この辺りが最後に侵食体を発見した場所です。","ENG":"This is the place where the C.O. was last spotted.","TWN":"前面就是最後捕捉到侵蝕體的地方。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"Brrr...","TWN":"呼……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"갑자기 추워진 것 같아요. 등이 시려운 느낌…","JPN":"いきなり寒くなった気がします。背中が寒い感じ……","ENG":"It suddenly feels cold. My back is chilly.","TWN":"好像突然變冷了，有種背後發涼的感覺……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"긴장할 거 없어. 이 언니가 곁에 있으니까.","JPN":"緊張しなくてもいいよ。お姉ちゃんがついてるから。","ENG":"There's no need to be tense. I'm here with you.","TWN":"不用緊張，有姊姊我在。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네! 언니!","JPN":"はい！　姉さん！","ENG":"Okay, Sis!","TWN":"好的！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼, 긴장이라도 풀 겸 다 같이 파이팅 하고 갈까요?","JPN":"では、緊張をほぐすためにみんなで円陣を組んで気合を入れてから行きましょうか？","ENG":"Then, how about we all shout \\"hurrah\\" to ease the tension?","TWN":"那……正好放鬆一下緊張情緒，大家一起加油打氣怎麼樣？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아, 쫌- 촌스럽다고. 그런 거.","JPN":"マエカワ警部補、ダサいわよ。そういうの。","ENG":"Ugh, that's so old-fashioned.","TWN":"很俗欸，姜素英警官。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"파이팅? 그게 뭐죠?","JPN":"気合？　それは何ですか？","ENG":"Hurrah? What's that?","TWN":"加油？那是什麼？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"간단한 구호랍니다. 이걸 외치고 작전을 시작하면 일이 잘 풀리거든요.","JPN":"簡単な掛け声です。これを叫んでから作戦を始めると上手くいくんですよ。","ENG":"It's a simple cheer. When we shout this and start the operation, things usually go well.","TWN":"就是簡單的口號啦。喊一下然後再開始行動的話，便能萬事順利。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아하, 꽃반지 같은 거군요.","JPN":"あは、花の指輪みたいなものですね。","ENG":"Ah, it's like a flower ring.","TWN":"啊哈，就跟花戒指是一樣的道理是吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"꽃반지? 그렇게 외치는 동네도 있어?","JPN":"花の指輪？　そう叫ぶところもあるんですか？","ENG":"Flower ring? Is there a neighborhood where they shout that out?","TWN":"花戒指？現在還流行花戒指嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아무튼 시간 없으니까. 할 거면 빨리 하고 가자.","JPN":"とにかく時間がないから。やるならさっさとやって行くわよ。","ENG":"Anyway, we don't have much time. If we're going to do this, let's hurry up and get it over with.","TWN":"總之沒時間了，要喊加油就快點，然後出發吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"알겠죠? 셋 세고 손을 번쩍 들면서 파이팅! 하고 외치는 거예요.","JPN":"いいですね？　3つ数えたら手を挙げてファイト！と叫びますよ。","ENG":"Got it? On three, raise your hand and shout, \\"hurrah!\\"","TWN":"準備好了嗎？數到三然後把手舉起來，大聲喊加油！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네!","JPN":"はい！","ENG":"Okay!","TWN":"好！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"하나-","JPN":"いーち","ENG":"One!","TWN":"一……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"두울-","JPN":"にー","ENG":"Two!","TWN":"二……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"세엣-","JPN":"さーん","ENG":"Three!","TWN":"三！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"응…? 잠깐.","JPN":"ん……？　ちょっと待って。","ENG":"Hmm...? Wait.","TWN":"嗯……？ 等一下。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"화이팅-!!!!!","JPN":"ファイトー！！！","ENG":"Hurrah!!!","TWN":"加油！！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…다들 뭐야?! 왜 나 혼자만 외치는 건데!","JPN":"……な、何よみんな！？　何で私だけ叫ぶの！","ENG":"...What's going on? Why am I the only one who shouted it?","TWN":"……你，你們怎麼回事？！為什麼只有我一個人在喊？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"방금 저 골목 사이에서, 뭔가 움직였어요.","JPN":"今あの路地裏で何か動いたような……","ENG":"I think I saw something move between those alleys.","TWN":"剛剛那條巷子裡好像有什麼東西在動……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"…쳇!","JPN":"……ちっ！","ENG":"...Tch!","TWN":"……哼！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 도망쳤어요!","JPN":"あっ、逃げました！","ENG":"Ah, it ran away!","TWN":"啊，跑掉了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"쫓아가자!","JPN":"追うよ！","ENG":"Let's chase it!","TWN":"快追上去！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"으이씨, 숨 차.","JPN":"はぁ……はぁ……きっつー","ENG":"Ugh, I'm out of breath.","TWN":"可惡，喘不上氣了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"하필 재수 없게 캔을 밟을 줄이야…","JPN":"よりにもよってあそこで缶を踏むとかありえないし……","ENG":"How unlucky, stepping on a can like that...","TWN":"真是倒楣，偏偏踩到了罐子……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그래도 이 골목만 돌면 개구멍이 있으니 따돌릴 수 있…!","JPN":"でもこの角さえ曲がれば小さい穴があるから逃げられる……！","ENG":"But if I turn this corner, there's a small hole in the wall, so I can lose–!","TWN":"不過只要拐過這個巷子就有個小洞可以鑽，到時候就能甩掉……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"이 철책은 뭐지? 어제까지만 해도 이런 걸로 막혀있지 않았는데…?","JPN":"この鉄柵はなんだ？　昨日まではこんなので塞がっていなかったのに……？","ENG":"What's with this wire fence? It wasn't like this just yesterday.","TWN":"這鐵柵欄是怎麼回事？昨天明明還沒有的……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"으아앗!!","JPN":"うわあっ！！","ENG":"No!!","TWN":"哇啊啊！！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"이… 이건 철책이 아니라…","JPN":"こ……これは鉄柵じゃなく……","ENG":"This... this isn't a wire fence, it's...","TWN":"這……這不是鐵柵欄……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그물이잖아?","JPN":"網なのか？","ENG":"A net?","TWN":"是漁網？！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그 침식체 녀석일 것 같아서 쏘려다 말았는데… 너 운이 좋네.","JPN":"あの侵食体だと思って撃とうとしてやめたけど……あなた運がいいわ。","ENG":"I was going to shoot because I thought you might be that C.O.... You're lucky.","TWN":"剛才以為是那個侵蝕體，差點就開槍了……算你命大。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"왜 아직 여기 있는 거야? 대피 방송을 못 들었다고 하진 않겠지?","JPN":"何でまだここにいるの？　避難放送を聞いてないとは言わないよね？","ENG":"Why are you still here? You're not going to say that you missed the evacuation announcement, right?","TWN":"你怎麼還在這裡？別告訴我你沒聽到疏散廣播。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"이거 풀어주기나 해. 난 나갈 생각 없으니까.","JPN":"これ解いてよ。私は出る気はないから。","ENG":"Just untie me. I'm not going out.","TWN":"快把這個解開，我根本就沒打算要出去。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"너 지금 이 상황이 이해가 안돼?","JPN":"あなた、今の状況が理解できないの？","ENG":"Do you not understand the situation?","TWN":"你還沒搞清楚狀況嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"침식체가 언제 나타나 널 해쳐도 도와줄 사람이 없단 뜻이라고.","JPN":"いつ侵食体が現れてあなたを攻撃しても、助けてくれる人が誰もいないってことよ。","ENG":"It means that if a C.O. shows up and attacks you, there's no one to help you.","TWN":"如果侵蝕體突然出現，沒有人救得了你。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그럼 그냥 운이 없는 거지 뭐.","JPN":"そしたら運が悪かったって思うよ。","ENG":"Then I guess I'm just unlucky.","TWN":"那也就只能怪自己運氣不好。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"너, 이 도시 주민이 아니지?","JPN":"あなた、この都市の住民ではないわね？","ENG":"You're not a resident of this city, are you?","TWN":"喂，你不是這個城市的居民吧？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"아, 아니거든? 난 여기서 태어났어.","JPN":"ち、違うよ？　私はここで生まれたんだ！","ENG":"Y-yes I am! I was born here.","TWN":"說，說什麼呢？！我可是土生土長的本地人！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그럼 집은 어디야? 적어도 안전한 곳에 있어야지. 왜 길거리에 숨어있었어?","JPN":"じゃあ家はどこ？　少なくとも安全な場所にいないと。何で路地裏に隠れているの？","ENG":"Then where's your home? You should at least be somewhere safe. Why were you hiding in the street?","TWN":"那你家在哪？至少應該待在安全的地方吧，為什麼躲在街頭？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"윽… 그건…","JPN":"うっ……それは……","ENG":"Ngh... that's...","TWN":"呃……那個……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 언니! 멍청이를 찾았군요!","JPN":"あっ、姉さん！　バカを見つけたんですね！","ENG":"Oh, Sis! You found a fool!","TWN":"啊，姊姊！看來你找到傻子了！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"잠깐… 방금 나보고 멍청이라고 한 거야?!","JPN":"ちょ……今私にバカって言った！？","ENG":"Wait… Are you calling me a fool?!","TWN":"說誰是傻子呢？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어?","JPN":"あれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"당신은… 그때 만났던 사람?","JPN":"あなたは……あの時会った人？","ENG":"You're... that person I met back then!","TWN":"你是……那時候遇到的那個人？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"윽? 넌…?!","JPN":"うっ？　あんた……！？","ENG":"Ngh! You're...!","TWN":"呃？！你是……？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"왜 그래, 솔로베? 아는 사람이야?","JPN":"どうしたの、ソロベー？　知り合い？","ENG":"What's wrong, Solovey? Do you know her?","TWN":"怎麼了，蘇羅薇？你認識她？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"알아요.","JPN":"はい。","ENG":"I do.","TWN":"認識。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저한테 약값이 필요하다고 했던 그 아이거든요.","JPN":"私に薬代が必要だと言った子です。","ENG":"She's the one who told me she needed money for her medicine.","TWN":"她就是跟我說媽媽需要手術費的那個孩子。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"호오…? 너였구나?","JPN":"へぇ……？　あなただったんだ？","ENG":"Oh...? So it was you!","TWN":"喔……原來是你？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_HATE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"순진한 내 동생을 속이고 돈을 몽땅 가져갔다는 녀석이.","JPN":"無邪気な私の妹を騙して、お金を全部持って行ったやつが。","ENG":"The one who deceived my innocent sister and took all her money.","TWN":"就是你騙了我天真的妹妹！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"윽…?!","JPN":"うっ……！？","ENG":"Ngh…!?","TWN":"呃……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"신원이 조회되지 않네요. 아무래도 불법 거주민이었던 모양이에요.","JPN":"身元が確認できません。どうやら不法滞在者のようですね。","ENG":"There are no records of her identity. It seems like she is an illegal resident.","TWN":"身份無法查詢，看來是非法居民。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"침식체도 아니면서 왜 도망치나 했더니, 그런 이유였어?","JPN":"侵食体でもないのに何で逃げるのかと思ったら、そういう訳だったの？","ENG":"I wondered why she was running away despite not being a C.O. But that was the reason, huh?","TWN":"就說嘛，你又不是侵蝕體，為什麼還要逃跑呢？原來是這樣！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…불법 거주자를 잡으면 어떻게 하는데?","JPN":"……不法居住者を捕まえたらどうなるの？","ENG":"...What happens if we catch illegal residents?","TWN":"……抓住非法居民後，應該怎麼辦？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"적법한 심사를 거쳐 추방 여부를 결정하죠.","JPN":"適法な審査を経て追放するかしないかを決めます。","ENG":"They'll go through the legal process of evaluation, and their deportation will be decided.","TWN":"需要經過合法審查，然後決定是否驅逐。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"보통은 범죄자나 밀입국자들이 추방을 우려해서 숨어 지내지만…","JPN":"一般的に犯罪者や密入国者は追放されるのが怖くて隠れて過ごすんですが……","ENG":"Usually, criminals or illegal immigrants stay in hiding for fear of deportation...","TWN":"通常罪犯或非法入境者會因害怕被驅逐而躲藏起來……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저 애는 범죄는커녕 출생신고이력도 없어요.","JPN":"あの子は犯罪歴はおろか、出生届の履歴もありません。","ENG":"But that child has no criminal record. Not even a birth registration history!","TWN":"但這個孩子不僅沒有犯罪記錄，甚至連出生記錄都沒有。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"응? 그 말은 심사만 받으면 시민이 될 수 있다는 건가?","JPN":"ん？　つまり、審査さえ受ければ市民にもなれるってこと？","ENG":"Huh? Does that mean she could become a citizen if she just goes through the evaluation?","TWN":"嗯？也就是說，只要接受審查，就能成為公民？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"큰 문제만 없다면 그렇겠죠. 큰 범죄를 저지르고 도망쳤다던가, 침식 질환에 노출됐다던가 하지만 않으면요.","JPN":"大きな問題がなければの話です。重罪を犯して逃げているとか、侵食疾患に露出したとか。","ENG":"If there are no major issues, yes. As long as she hasn't committed serious crimes, fled after committing one, or been exposed to Corruption illness.","TWN":"如果沒有特殊情況，應該是的。只要不是因重大犯罪逃亡或受到侵蝕疾病感染，就沒問題。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"잘 됐네. 딱히 침식증후군 환자도 아닌 것 같은데, 지금이라도 심사를 받는 게 어때?","JPN":"よかったわね。別に侵食症候群の患者でもないようだけど、今でも審査を受けたらどう？","ENG":"Good. You don't seem like someone with Corruption Syndrome. Why don't you go through the evaluation?","TWN":"你怎麼畏畏縮縮的？看起來也不像是侵蝕症候群患者啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"저기…","JPN":"あの……","ENG":"Hey...","TWN":"那個……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그냥 못 본 척 해주면 안돼요? 시민증 같은 거 관심 없어. 여길 떠나면 안 된다고요.","JPN":"見なかったことにはできませんか？　市民証なんて興味ないです。ここから離れたらダメなんですよ。","ENG":"Can't you just pretend you didn't see me? I don't care about the citizen status. I need to stay here.","TWN":"求求你們！能不能就當沒看到我？我必須留在這裡！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"괜한 고집 부리지 마.","JPN":"意地を張らないで。","ENG":"That's not possible.","TWN":"那當然不行。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"널 여기 내버려두면 우리 일에 계속 방해가 된다고.","JPN":"あなたをここに放っておくと私たちの仕事の邪魔になるの。","ENG":"If we leave you here, you'll keep interfering with what we need to do.","TWN":"如果把你留在這裡，只會妨礙我們的工作。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"솔로베 양, 저 아이가 수술비 때문에 당신의 돈을 받아갔다고 했었죠?","JPN":"ソロベーさん、あの子が手術費用のためにあなたからお金を貰っていったと言いましたよね？","ENG":"Solovey, didn't you say that child took your money for her mother's surgery?","TWN":"蘇羅薇，這個孩子之前說是因為需要媽媽的手術費才向你借錢的，對吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아, 네!","JPN":"あっ、はい！","ENG":"Ah, yes!","TWN":"啊，是的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니 어머니는 어때요? 그 돈으로 아픈 건 나았나요?","JPN":"そういえば、お母さんは大丈夫ですか？　そのお金で痛いのは直りました？","ENG":"By the way, how's your mother doing? Did the money help with her illness?","TWN":"那麼話說回來，你媽媽怎麼樣了？用那筆錢把病治好了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그… 그건…","JPN":"そ……それは……","ENG":"Th-that's...","TWN":"這……那個……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"질문이 틀렸어, 솔로베. 이 앤 그냥 너한테서 돈을 빼앗으려 거짓말한 거라고.","JPN":"違うよ、ソロベー。この子はあなたから金をだまし取るためにウソついただけだよ。","ENG":"You're mistaken, Solovey. She lied just to take money from you.","TWN":"你被騙了，蘇羅薇。這個孩子只是想從你那裡騙錢罷了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그게… 정말인가요?","JPN":"それは……本当ですか？","ENG":"Is that... really true?","TWN":"這……是真的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"…미안.","JPN":"……ごめん。","ENG":"...Sorry.","TWN":"……對不起。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 오히려 잘 됐어요. 거짓말이면 아무도 아프지 않은 거니까.","JPN":"大丈夫。むしろよかったです。ウソだったなら誰も痛くなかったってことですから。","ENG":"It's okay. It's actually a good thing. If it's a lie, no one is sick.","TWN":"沒關係，這樣反倒更好。如果是說謊，就說明沒有人真的生病受苦不是嘛。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 제 돈을 돌려받아도 될까요? 언니한테 갚을 돈이 있거든요.","JPN":"では、私のお金を返してもらってもいいですか？　姉さんに返さなければならないお金が溜まってて。","ENG":"Then, can I get my money back? I owe some to Sis.","TWN":"那麼，我可以把我的錢拿回來嗎？我還欠姊姊不少錢呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"갚을 돈?","JPN":"返すお金？","ENG":"Owe a lot?","TWN":"欠錢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"으흠… 금전 개념이 희박한 아이라 교육이 필요해서요.","JPN":"こほん……金銭感覚がないような子でして、教育が必要なんです。","ENG":"Ahem... The child has a poor understanding of money, so she needs some guidance.","TWN":"咳咳……因為這孩子太沒有金錢觀念，需要教育一下。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"돈은 없어. 이미 다 썼거든.","JPN":"お金はない。もう全部使った。","ENG":"I don't have the money. I already spent it all.","TWN":"要錢沒有，已經全部花掉了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그렇다면 범죄 성립이네.","JPN":"なら犯罪成立ね。","ENG":"In that case, it's a crime.","TWN":"那樣的話就構成犯罪了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이렇게 된 이상, 심사고 뭐고 강제로 연행해주겠어.","JPN":"こうなった以上、審査なんて関係なしに強制連行する。","ENG":"At this point, forget about evaluation. I'll arrest her as a criminal.","TWN":"既然如此，別管市民證什麼的了，直接當作罪犯帶走吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"시, 싫어!","JPN":"い、いやだ！","ENG":"No, I don't want that!","TWN":"不，不要！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"난 여길 떠나면 안돼!","JPN":"私はここを離れちゃダメなんだ！","ENG":"I can't leave here!","TWN":"我不能進監獄！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"사라졌잖아? 카운터였어?","JPN":"消えた？　カウンターだったの？","ENG":"She disappeared! Was she a Counter?","TWN":"就這麼消失了？難道是超能力？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"별일이네요. 순간이동 계열은 엄청 드문데.","JPN":"珍しいですね。瞬間移動系はめったにいないのに。","ENG":"That's unusual. Space-jumping abilities aren't that common.","TWN":"這倒是新鮮，空間移動能力可不常見。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어쩌죠? 갑자기 사라져버렸어요.","JPN":"どうしましょう？　いきなり消えてしまいました。","ENG":"What should we do? She suddenly disappeared.","TWN":"怎麼辦？就這麼憑空消失了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"바로 도망치지 못한 걸 보면 능력이 익숙하지 않다는 거에요.","JPN":"すぐ逃げなかったってことは、まだ能力を使いこなせないってことです。","ENG":"The fact that she couldn't escape right away means she's not familiar with her ability.","TWN":"既然沒有立刻逃跑，說明她還無法熟練掌握自己的能力。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"두 팀으로 나눠서 근처를 확인해보죠.","JPN":"二手に分かれてこの周辺を探してみましょう。","ENG":"Let's split into two teams and check the area.","TWN":"分成兩組，在附近搜查一下吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"발소리구나.","JPN":"足跡が聞こえるわ。","ENG":"I hear footsteps.","TWN":"能聽到腳步聲。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"애니가 돌아온 거니?","JPN":"エニー、戻ったの？","ENG":"Is that you, Annie?","TWN":"安妮，是你回來了嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"응, 혼자 둬서 미안. 헤일리.","JPN":"うん、1人にしてごめんね。ヘイリー。","ENG":"Yeah, sorry for leaving you alone, Hailey.","TWN":"嗯，抱歉讓你一個人待著，海莉。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"사람이 없을 때 병원에 가면 약이 있을까 했는데, 아무것도 못 찾았어.","JPN":"人がいない時に病院にいけば薬があると思ったけど、何も見つけられなかった。","ENG":"I thought there might be medicine at the hospital when no one was around, but I couldn't find anything.","TWN":"我想著趁沒人時去醫院找點藥，結果還是什麼都沒找到。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"콜록… 난 괜찮다니까.","JPN":"ゲホ……私は大丈夫よ。","ENG":"*Cough...* I'm fine, really.","TWN":"咳咳……我沒事的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"다음엔 그러지 마. 도둑질은 나쁜 거랬잖니.","JPN":"次からはやめなさい。泥棒は悪いことだと言ったでしょう。","ENG":"Don't do that again next time. I told you that stealing is wrong.","TWN":"下次別這樣，我告訴過你，偷東西是不對的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그럼 어떡해? 헤일리가 아픈 건 싫단 말이야!","JPN":"じゃあどうすればいいの？　ヘイリーが痛いのは嫌なんだよ！","ENG":"Then what am I supposed to do? I don't want to see you sick, Hailey.","TWN":"那我能怎麼辦？我不想看著你生病受苦！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"그건 다 내 잘못이야. 위험하단 걸 알면서도, 고양이를 찾으려고 침식지대에 들어갔다가 얻은 병이니까.","JPN":"それは全部私が悪いの。危険だとわかっていて猫を探すために侵食地帯に入って病気にかかったんだから。","ENG":"It's all my fault. I went into the Corrupted Area knowing it was dangerous, just to find my one and only cat.","TWN":"都是我的錯，明明知道危險還跑進侵蝕區，就為了找回我唯一的貓……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"내 잘못을 네가 감당할 필요는 없어.","JPN":"私の失敗で、あなたが苦労する必要はないの。","ENG":"So there's no need for you to try so hard.","TWN":"所以你不需要這麼拼命。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"이터니움 정제액…!","JPN":"エタニウム精製水……！","ENG":"Purified Eternium liquid...!","TWN":"永恆之金淨化液……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"그거 맞고 나서 며칠 동안은 멀쩡했잖아! 내가 그것만 계속 구해주면 언젠가 나을 거라고!","JPN":"それを打ってもらってから何日かは元気だったよね！　ずっとそれが手に入れば、いつかは治るよ！","ENG":"You were fine for a few days after taking that! If I keep bringing it, you'll get better eventually!","TWN":"你用了那個藥後不是好了很多天嗎？只要我能再多找些藥，遲早能治好的！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"욘석아. 그런 거 100개가 있어도 소용없어. 내 몸은 내가 알아.","JPN":"こら。そんな物は100個あっても無駄よ。自分の体は自分が一番よくわかっている。","ENG":"Don't be silly. Even if I took a hundred of those, it wouldn't help. I know my body.","TWN":"傻孩子，就算有一百瓶也沒用，我的身體我自己清楚。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"아니! 헤일리는 아무 것도 몰라! 지금 내가 어떤 심정인지도 모르는 거잖아!","JPN":"いいや！　ヘイリーは何も知らないんだ！　今私がどんな気持ちなのかも知らないくせに！","ENG":"No, Hailey! You don't know anything! You don't even know how I'm feeling right now!","TWN":"不！海莉你什麼都不懂！你根本不理解我現在的心情！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"언니.","JPN":"姉さん。","ENG":"Sis.","TWN":"姊姊。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그냥 못 본 척하고 돌아가면 안돼요? 돈은 괜찮으니까…","JPN":"見なかったことにして戻りませんか？　お金はもういいから……","ENG":"Can't we just pretend we didn't see this and go back? I don't care about the money anymore...","TWN":"就當什麼都沒看見，回去行嗎？錢的事無所謂的……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"아니. 여기까지 와서 내버려두면 더 나빠질 뿐이야.","JPN":"いいえ。ここまで来て放っておくと、もっと悪化するだけ。","ENG":"No. I can't just pretend not to notice after coming this far.","TWN":"不，事到如今，怎麼能裝作不知道呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이제 그만 포기해, 애니.","JPN":"もう諦めなさい、エニー。","ENG":"It's time to give up, Annie.","TWN":"安妮，放棄吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"당신들?! 어떻게 여길 들어온 거야?","JPN":"あんたたち！？　いったいどうやってここに入ったの？","ENG":"You two?! How did you get in here?","TWN":"你們？！是怎麼進來的？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"너처럼 능력이 미숙한 애들은 흔적이 남거든.","JPN":"あなたのように能力が未熟な子は痕跡が残るの。","ENG":"Amateurs like you with unrefined abilities leave traces.","TWN":"像你這種能力尚不成熟的人，總會留下些蛛絲馬跡的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"윽… 그럴 수가.","JPN":"うっ……そんな。","ENG":"Ngh... This can't be.","TWN":"呃……怎麼會……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"그냥 감으로 찾은 것 뿐이지만, 사실대로 말하면 또 어디로 튈 지 모르니까.","JPN":"ただの勘で見つけたんだけど、事実を言ったらまた逃げるかもしれないし。","ENG":"I just followed my instincts to find her, but if I tell her the truth, I don't know where she will run away to again.","TWN":"雖說其實是憑感覺找到的，但如果告訴你實話，你可能又會跑掉吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"날… 잡아갈 거야?","JPN":"私を……捕まえるの？","ENG":"Are you... going to take me away?","TWN":"你們……要抓我走嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"저 사람은 네 진짜 엄마가 아니지?","JPN":"あの人はあなたの本当のお母さんじゃないでしょ？","ENG":"She isn't your real mother, is she?","TWN":"那個女人，不是你的親生媽媽吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"가족도 아닌 사람을 살리려고 범죄를 저지르는 게, 정말 옳은 일인 것 같아?","JPN":"家族でもない人を助けるために犯罪を犯すことが正しいことだと思う？","ENG":"Do you think it's right to commit a crime just to save someone who isn't your family?","TWN":"為了救一個毫無血緣關係的人而犯罪，值得嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"네가 카운터라면 좀 더 나은 일에 그 힘을 쓰는 편이 낫지 않겠어?","JPN":"あなたがカウンターなら、よりいいことにその力を使ったほうがいいんじゃないの？","ENG":"If you're a Counter, shouldn't you use your power for something better?","TWN":"如果你是制裁者，將這份力量用在更好的地方不是更好嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"이…!","JPN":"この……！","ENG":"Why you...!","TWN":"這……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"아무것도 모르면서 그런 말 하지 마!","JPN":"何も知らないくせにそんなこと言わないで！","ENG":"Don't say something like that when you don't understand anything!","TWN":"什麼都不知道就不要亂說！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"헤일리가 없으면 난 아무것도 아니라고!","JPN":"ヘイリーは私の全てなの！　ヘイリーがいなければ私はなんでもないんだから！","ENG":"Without Hailey, I'm nothing!","TWN":"海莉是我的全部！如果沒有海莉，我就什麼都不是了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"글쎄? 아무것도 모르는 건 네가 아닐까?","JPN":"さあね？　何も知らないのはあなたの方みたいだけど？","ENG":"It seems like you're the one who doesn't understand anything.","TWN":"是嗎？我倒覺得什麼都不知道的人是你啊？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"침식증후군은 치료할 수 없어. 돈 많은 재벌도, 권위 있는 대통령도 못 고치는 병이야.","JPN":"侵食症候群は治療できない。お金持ちの財閥も、権威のある大統領も治せない病なの。","ENG":"Corruption Syndrome is incurable. No amount of money or power can fix it.","TWN":"侵蝕症候群是無法治癒的病，就算是富可敵國的財閥，或者位高權重的總統也束手無策。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"넌 지금 밑 빠진 독에 물을 붓고 있는 거라고. 네 인생을 망쳐가면서까지.","JPN":"あなたは今意味のないことをしているのよ。自分の人生をダメにしてまで。","ENG":"Right now, you're just trying to fill a bottomless pit, ruining your life in the process.","TWN":"你就像拼命往破碎的罐子裡注水的人，甚至不惜為此毀掉你的人生。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"그럼 어떡해? 나보고 대체 어쩌란 건데?!","JPN":"じゃあどうする？　私にいったいどうしろっていうの！？","ENG":"Then what should I do? What are you telling me to do?","TWN":"那我該怎麼辦？！你要我怎麼辦？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"…떠나.","JPN":"……行きなさい。","ENG":"...Leave.","TWN":"……離開吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"헤일리…?","JPN":"ヘイリー……？","ENG":"Hailey...?","TWN":"海莉？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"넌 워치도 있는 카운터잖니. 나 같은 집도 연줄도 없는 부랑자를 돌보느라 네 삶을 망치지 마.","JPN":"あなたはウォッチも持っているカウンターじゃない。私みたいに家もコネもないホームレスの面倒を見るためにあなたの人生を台無しにしないで。","ENG":"You're a Counter with a Watch, aren't you? Don't ruin your life taking care of someone like me, a homeless nobody with no connections.","TWN":"你可是有能量環的制裁者。別為了照顧像我這樣無家可歸、毫無背景的流浪者而毀了自己的人生。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OLDWOMAN_NPC_WITH_ANNIE","text":{"KOREA":"넌 충분히 노력했어. 이젠 날 내버려둬. 자유롭고 멋진… 너만의 삶을 살아.","JPN":"あなたは十分努力したよ。私のことはもういいから。自由で素敵な……あなただけの人生を生きて。","ENG":"You've done enough. Now let me go. Live your own free and beautiful life.","TWN":"你已經盡力了，放下我吧。去過自由精彩……屬於你自己的人生"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"당신 내버려두고… 살라고?","JPN":"あんたを放っておいて……生きろって？","ENG":"You want me to abandon you... and live?","TWN":"丟下你……我自己要怎麼活下去？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"내가 이렇게 애쓰고 있는데, 왜 혼자 벌써 포기하는 건데?!","JPN":"こんなに私が頑張っているのに、なんで1人で簡単に諦めるの！？","ENG":"I'm putting in all this effort, and yet you're giving up already on your own! Why?!","TWN":"我這麼努力，你憑什麼這麼輕易就放棄？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NULL","text":{"KOREA":"다 미워! 밉다고!","JPN":"みんな嫌い！　嫌いだよ！","ENG":"I hate you for everything! I hate you!","TWN":"討厭！我討厭你們！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILD_NPC_ANNIE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗… 사라졌어요.","JPN":"あっ……消えました。","ENG":"Ah... She disappeared.","TWN":"啊……消失了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"휴우, 손 많이 가네.","JPN":"ふう、手のかかる子ね。","ENG":"Phew, this takes a lot of work.","TWN":"呼……真是麻煩。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"크윽, 간신히 찾았는데 또 도망쳤잖아!","JPN":"くっ、ようやく見つけたのにまた逃げたの！","ENG":"Ugh, we finally found her and she got away again!","TWN":"嘖，真煩人……！好不容易才找到，又讓她跑了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"대화하기 전에 수갑부터 채워뒀어야 했는데.","JPN":"話す前に手錠からかけるべきだった。","ENG":"I should've put her in handcuffs first before talking.","TWN":"果然應該一開始就給她戴上手銬。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"다시 찾아보죠. 보호가 필요한 사람을 두고 멀리 가진 않을 거에요.","JPN":"また探しましょう。保護が必要な人を置いてそう遠くまでは行けないはずです。","ENG":"Let's search again. She wouldn't have gone far leaving someone who needs protection.","TWN":"繼續找吧，不會跑遠的，畢竟她還有想要保護的人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"솔로베, 네가 여길 지키고 있어. 언제 다시 돌아올 지 모르니까.","JPN":"ソロベー、ここはあなたが守っていて。また戻ってくるかもしれないから。","ENG":"Solovey, you stay here, since we don't know when she'll return.","TWN":"蘇羅薇，你留在這裡。她隨時可能會回來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네, 알겠어요!","JPN":"はい、わかりました！","ENG":"Okay!","TWN":"啊，知道了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"서두르자! 이번에야말로 안 봐줘!","JPN":"急ごう！　今度こそ逃がさない！","ENG":"Let's hurry! I won't go lenient this time!","TWN":"趕快！這次絕不能再讓她跑了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};